import{_ as t,o as e,c as r,a2 as n}from"./chunks/framework.Bix3-HpO.js";const d=JSON.parse('{"title":"How To ...","description":"FXT Theme - How to Guide","frontmatter":{"title":"How To ...","description":"FXT Theme - How to Guide","weight":200,"extra":{"order":200},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/fxt/how-to"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/fxt/how-to"}],["meta",{"property":"og:title","content":"How To ..."}],["meta",{"property":"og:description","content":"FXT Theme - How to Guide"}],["meta",{"name":"twitter:title","content":"How To ..."}],["meta",{"name":"twitter:description","content":"FXT Theme - How to Guide"}]]},"headers":[],"relativePath":"docs/fxt/how-to.md","filePath":"docs/fxt/how-to.md"}'),s={name:"docs/fxt/how-to.md"};function i(a,o,l,h,g,p){return e(),r("div",null,[...o[0]||(o[0]=[n('<h1 id="how-to" tabindex="-1">How To ... <a class="header-anchor" href="#how-to" aria-label="Permalink to &quot;How To ...&quot;">​</a></h1><p>This guide provides step-by-step instructions for common tasks and customizations in FXT theme.</p><hr><h2 id="how-to-change-the-broker-page-slug" tabindex="-1">How to Change the Broker Page Slug <a class="header-anchor" href="#how-to-change-the-broker-page-slug" aria-label="Permalink to &quot;How to Change the Broker Page Slug&quot;">​</a></h2><p>The broker page slug determines the URL structure for your broker pages.</p><ol><li>Go to <strong>FXT Options</strong> → <strong>Main Options</strong></li><li>Find the <strong><a href="/docs/fxt/theme-options#broker-options">Broker Options</a></strong> section</li><li>Locate the <strong>Broker Page Slug</strong> field</li><li>Enter your desired slug (e.g., &quot;brokers&quot;, &quot;forex-brokers&quot;, &quot;trading-brokers&quot;)</li><li>Click <strong>Save</strong></li><li>Update your permalinks: <strong>Settings</strong> → <strong>Permalinks</strong> → <strong>Save Changes</strong></li></ol><p><strong>Important Notes</strong>:</p><ul><li>Use lowercase letters, numbers, and hyphens only</li><li>Avoid spaces and special characters</li><li>The slug will be used in URLs like: <code>yoursite.com/brokers/broker-name</code></li><li>Changing the slug will affect existing broker page URLs</li></ul><hr><h2 id="how-to-enable-disable-rich-snippets" tabindex="-1">How to Enable/Disable Rich Snippets <a class="header-anchor" href="#how-to-enable-disable-rich-snippets" aria-label="Permalink to &quot;How to Enable/Disable Rich Snippets&quot;">​</a></h2><p>Rich snippets provide structured data for search engines to better understand your content.</p><ol><li>Go to <strong>FXT Options</strong> → <strong>Main Options</strong></li><li>Find the <strong><a href="/docs/fxt/theme-options#broker-options">Broker Options</a></strong> section</li><li>Toggle the <strong>Rich Snippets</strong> option on/off</li><li>Set the <strong>Rich Snippet Author</strong> if enabled</li><li>Click <strong>Save</strong></li></ol><hr><h2 id="how-to-enable-disable-author-blocks" tabindex="-1">How to Enable/Disable Author Blocks <a class="header-anchor" href="#how-to-enable-disable-author-blocks" aria-label="Permalink to &quot;How to Enable/Disable Author Blocks&quot;">​</a></h2><p>Author blocks display author information on your content pages.</p><ol><li>Go to <strong>FXT Options</strong> → <strong>Main Options</strong></li><li>Choose the content type: <ul><li><strong>Broker Options</strong>: For broker pages</li><li><strong>Page Options</strong>: For regular pages</li><li><strong>Post Options</strong>: For blog posts</li></ul></li><li>Toggle the <strong>Author Block</strong> or <strong>Author Full Block</strong> options</li><li>Click <strong>Save</strong></li></ol><p><strong>Block Types</strong>:</p><ul><li><strong>Author Block</strong>: Basic author information near the page title</li><li><strong>Author Full Block</strong>: Extended author information with bio and avatar at the end of the page</li></ul><hr><h2 id="how-to-enable-disable-table-of-contents" tabindex="-1">How to Enable/Disable Table of Contents <a class="header-anchor" href="#how-to-enable-disable-table-of-contents" aria-label="Permalink to &quot;How to Enable/Disable Table of Contents&quot;">​</a></h2><p>Table of Contents (TOC) provides navigation for long-form content.</p><ol><li>Go to <strong>FXT Options</strong> → <strong>Main Options</strong></li><li>Choose the content type: <ul><li><strong>Broker Options</strong>: For broker pages</li><li><strong>Page Options</strong>: For regular pages</li><li><strong>Post Options</strong>: For blog posts</li></ul></li><li>Toggle the <strong>Table of Contents</strong> option</li><li>Click <strong>Save</strong></li></ol><hr><h2 id="next-step" tabindex="-1">Next Step <a class="header-anchor" href="#next-step" aria-label="Permalink to &quot;Next Step&quot;">​</a></h2><p>You&#39;ve completed the FXT theme documentation! For additional help, refer to the <a href="https://codex.wordpress.org/" target="_blank" rel="noreferrer">WordPress Codex</a> or contact DinoMatic support.</p>',25)])])}const u=t(s,[["render",i]]);export{d as __pageData,u as default};
